import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"决斗系统","description":"","frontmatter":{},"headers":[],"relativePath":"guide/juedou.md","filePath":"guide/juedou.md","lastUpdated":null}'),d={name:"guide/juedou.md"};function i(o,t,n,h,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="决斗系统" tabindex="-1">决斗系统 <a class="header-anchor" href="#决斗系统" aria-label="Permalink to &quot;决斗系统&quot;">​</a></h1><p>修仙者之间的切磋较量，胜利可获得功德和荣誉，失败则要承受一定代价。</p><hr><h2 id="决斗参数" tabindex="-1">决斗参数 <a class="header-anchor" href="#决斗参数" aria-label="Permalink to &quot;决斗参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>决斗启用</td><td>✅</td><td>系统已启用</td></tr><tr><td>决斗冷却</td><td>120秒</td><td>发起决斗后冷却2分钟</td></tr><tr><td>最低境界</td><td>练气</td><td>凡人无法参与决斗</td></tr><tr><td>决斗超时</td><td>300秒（5分钟）</td><td>超时未分胜负自动结束</td></tr><tr><td>逃跑距离</td><td>120格</td><td>超出此距离视为逃跑</td></tr><tr><td>挑战响应超时</td><td>30秒</td><td>被挑战者需在30秒内回应</td></tr><tr><td>允许赌注</td><td>✅</td><td>可以押注物品</td></tr><tr><td>赌注上限</td><td>10个</td><td>最多押注10个物品</td></tr><tr><td>死亡扣灵气</td><td>20%</td><td>决斗失败扣除当前灵气的20%</td></tr></tbody></table><hr><h2 id="决斗流程" tabindex="-1">决斗流程 <a class="header-anchor" href="#决斗流程" aria-label="Permalink to &quot;决斗流程&quot;">​</a></h2><ol><li><strong>发起挑战</strong> — 使用 <code>/juedou &lt;玩家名&gt;</code> 向其他修士发起决斗</li><li><strong>等待响应</strong> — 被挑战者有 <strong>30秒</strong> 时间接受或拒绝</li><li><strong>进入战斗</strong> — 双方开始切磋，限时 <strong>5分钟</strong></li><li><strong>分出胜负</strong> — 一方死亡或逃跑则结束</li><li><strong>结算奖励</strong> — 胜者获得功德 +5，败者扣除20%灵气</li></ol><hr><h2 id="决斗规则" tabindex="-1">决斗规则 <a class="header-anchor" href="#决斗规则" aria-label="Permalink to &quot;决斗规则&quot;">​</a></h2><h3 id="胜利条件" tabindex="-1">胜利条件 <a class="header-anchor" href="#胜利条件" aria-label="Permalink to &quot;胜利条件&quot;">​</a></h3><ul><li>击杀对方</li><li>对方逃跑（超出120格范围）</li><li>对方超时未响应（自动判胜）</li></ul><h3 id="失败代价" tabindex="-1">失败代价 <a class="header-anchor" href="#失败代价" aria-label="Permalink to &quot;失败代价&quot;">​</a></h3><ul><li>扣除当前灵气的 <strong>20%</strong>（比普通死亡25%略低）</li><li>如果设了赌注，赌注归胜者所有</li></ul><h3 id="逃跑判定" tabindex="-1">逃跑判定 <a class="header-anchor" href="#逃跑判定" aria-label="Permalink to &quot;逃跑判定&quot;">​</a></h3><ul><li>决斗中任一方离开超过 <strong>120格</strong> 即判定逃跑</li><li>逃跑方视为失败，承受失败惩罚</li></ul><hr><h2 id="功德获取" tabindex="-1">功德获取 <a class="header-anchor" href="#功德获取" aria-label="Permalink to &quot;功德获取&quot;">​</a></h2><table tabindex="0"><thead><tr><th>行为</th><th>功德</th></tr></thead><tbody><tr><td>决斗胜利</td><td>+5</td></tr><tr><td>恶意击杀低境界玩家</td><td><strong>-200</strong>（境界差≥2）</td></tr></tbody></table><blockquote><p>⚠️ 公平决斗可以获得功德。但如果恶意击杀低于自己2个大境界以上的玩家，会受到天道严惩！</p></blockquote><hr><h2 id="决斗策略" tabindex="-1">决斗策略 <a class="header-anchor" href="#决斗策略" aria-label="Permalink to &quot;决斗策略&quot;">​</a></h2><h3 id="战前准备" tabindex="-1">战前准备 <a class="header-anchor" href="#战前准备" aria-label="Permalink to &quot;战前准备&quot;">​</a></h3><ol><li>确保灵气充足（功法需要灵气）</li><li>检查功法冷却状态</li><li>带好治疗丹/恢复丹</li></ol><h3 id="功法选择" tabindex="-1">功法选择 <a class="header-anchor" href="#功法选择" aria-label="Permalink to &quot;功法选择&quot;">​</a></h3><ul><li>防御型功法开局（护体罡气/金钟罩等）先保证生存</li><li>利用身法（缩地成寸）灵活走位</li><li>高威力攻击功法找时机爆发</li></ul><h3 id="灵根克制" tabindex="-1">灵根克制 <a class="header-anchor" href="#灵根克制" aria-label="Permalink to &quot;灵根克制&quot;">​</a></h3><ul><li>土灵根（高防御）克制火灵根（纯输出）</li><li>木灵根（高恢复）适合持久战</li><li>天灵根全属性优势，但觉醒概率仅5%</li></ul><hr><h2 id="赌注系统" tabindex="-1">赌注系统 <a class="header-anchor" href="#赌注系统" aria-label="Permalink to &quot;赌注系统&quot;">​</a></h2><p>决斗允许押注物品作为彩头：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/juedou &lt;玩家名&gt; &lt;赌注物品&gt; &lt;数量&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>最多押注 <strong>10个</strong> 物品</li><li>胜者获得全部赌注</li><li>败者失去赌注 + 20%灵气</li></ul><hr><h2 id="决斗礼仪" tabindex="-1">决斗礼仪 <a class="header-anchor" href="#决斗礼仪" aria-label="Permalink to &quot;决斗礼仪&quot;">​</a></h2><blockquote><p>⚔️ 修仙之路，以武会友。公平决斗是提升实力的最佳途径。</p><p>请勿恶意骚扰低境界修士，天道自然会惩罚不义之徒。</p></blockquote>',36)])])}const p=a(d,[["render",i]]);export{b as __pageData,p as default};
